SELECT c.customer_id, c.customer_name, l.loan_id 
FROM customers c 
INNER JOIN loans l ON c.customer_id = l.customer_id;

SELECT customers.customer_name, loans.loan_amount, loans.loan_status, loans.interest_rate
FROM loans
INNER JOIN customers ON loans.customer_id = customers.customer_id;

SELECT COUNT(*) AS term_count
FROM loan_terms
WHERE term_id IN (2, 3);

SELECT MIN(annual_income) AS lowest_income
FROM loans
WHERE loan_status = (SELECT status_id FROM loan_status WHERE status_name = 'Active');

SELECT AVG(credit_score) AS average_credit_score
FROM loans
WHERE loan_status = 1;

SELECT loan_id 
FROM loans 
WHERE loan_status = 1 AND term = 36;
